import pikepdf

def get_all_fields(pdf):
    """Recursively get all form fields"""
    fields = []

    def process_field(field_obj, prefix=""):
        if isinstance(field_obj, pikepdf.Array):
            for item in field_obj:
                process_field(item.resolve() if hasattr(item, 'resolve') else item, prefix)
            return

        if not isinstance(field_obj, pikepdf.Dictionary):
            return

        name = str(field_obj.get('/T', '')) if '/T' in field_obj else ''
        full_name = f"{prefix}.{name}" if prefix else name

        if '/Kids' in field_obj:
            for kid in field_obj['/Kids']:
                kid_obj = kid.resolve() if hasattr(kid, 'resolve') else kid
                process_field(kid_obj, full_name)
        else:
            field_type = str(field_obj.get('/FT', '')) if '/FT' in field_obj else ''
            value = str(field_obj.get('/V', '')) if '/V' in field_obj else ''
            fields.append((full_name, field_type, value))

    if '/AcroForm' in pdf.Root:
        acroform = pdf.Root['/AcroForm']
        if '/Fields' in acroform:
            field_list = acroform['/Fields']
            if isinstance(field_list, pikepdf.Array):
                for f in field_list:
                    fo = f.resolve() if hasattr(f, 'resolve') else f
                    process_field(fo)
            else:
                process_field(field_list)

    return fields

pdf = pikepdf.Pdf.open('f1040s1.pdf')
fields = get_all_fields(pdf)
for name, ftype, value in fields:
    print(f"{name} | {ftype} | {value}")
